import { RdfStore } from "rdf-stores";
import { DataFactory } from "rdf-data-factory";
import { getLoggerFor } from "../utils/index.js";
import { extractRelations } from "./relation.js";
const { namedNode } = new DataFactory();
export function longPromise() {
    const out = {};
    out.waiting = new Promise((res) => (out.callback = res));
    return out;
}
export function resetPromise(promise) {
    const cb = promise.callback;
    promise.waiting = new Promise((res) => (promise.callback = res));
    cb();
}
export async function statelessPageFetch(location, dereferencer, fetch_f) {
    const resp = await dereferencer.dereference(location, {
        localFiles: true,
        fetch: fetch_f,
    });
    const url = resp.url;
    const data = RdfStore.createDefault();
    await new Promise((resolve, reject) => {
        data.import(resp.data).on("end", resolve).on("error", reject);
    });
    return { url, data };
}
export class Fetcher {
    dereferencer;
    loose;
    fetch_f;
    condition;
    defaultTimezone;
    includeMetadata;
    closed = false;
    logger = getLoggerFor(this);
    constructor(dereferencer, loose, condition, defaultTimezone, includeMetadata, fetch_f) {
        this.dereferencer = dereferencer;
        this.loose = loose;
        this.fetch_f = fetch_f;
        this.condition = condition;
        this.defaultTimezone = defaultTimezone;
        this.includeMetadata = includeMetadata;
    }
    close() {
        this.closed = true;
    }
    async fetch(node, state, notifier) {
        try {
            const options = {
                localFiles: true,
                fetch: this.fetch_f,
            };
            if (this.includeMetadata) {
                options.headers = {
                    Accept: "application/metadata+trig",
                };
            }
            const resp = await this.dereferencer.dereference(node.target, options);
            node.target = resp.url;
            const cache = {};
            if (resp.headers) {
                const cacheControlCandidate = resp.headers.get("cache-control");
                if (cacheControlCandidate) {
                    const controls = cacheControlCandidate
                        .split(",")
                        .map((x) => x.split("=", 2).map((x) => x.trim()));
                    for (const control of controls) {
                        if (control[0] == "max-age") {
                            cache.maxAge = parseInt(control[1]);
                        }
                        if (control[0] == "immutable") {
                            cache.immutable = true;
                        }
                    }
                }
            }
            if (!cache.immutable) {
                if (!this.closed) {
                    notifier.scheduleFetch(node, state);
                }
            }
            this.logger.debug(`[fetch] Cache for ${node.target} ${JSON.stringify(cache)}`);
            const data = RdfStore.createDefault();
            let quadCount = 0;
            await new Promise((resolve, reject) => {
                resp.data
                    .on("data", (quad) => {
                    data.addQuad(quad);
                    quadCount++;
                })
                    .on("end", resolve)
                    .on("error", reject);
            });
            this.logger.debug(`[fetch] Got data ${node.target} (${quadCount} quads)`);
            const toFetch = [];
            for (const rel of extractRelations(data, namedNode(resp.url), this.loose, this.condition, this.defaultTimezone)) {
                if (!node.expected.has(rel.node) && rel.allowed) {
                    toFetch.push({ from: node, target: rel });
                }
            }
            if (!this.closed) {
                if (toFetch.length > 0) {
                    await notifier.relationsFound(toFetch, state);
                }
                notifier.pageFetched({
                    data,
                    url: resp.url,
                    immutable: !!cache.immutable,
                    memberCount: 0,
                }, state);
            }
        }
        catch (ex) {
            this.logger.error(`[fetch] Fetch failed for ${node.target} ${JSON.stringify(ex)}`);
            notifier.error(ex, state);
        }
    }
}
