import { NamedNode, Parser } from "n3";
import { DataFactory } from "rdf-data-factory";
import { extractShapes, pred } from "rdf-lens";
import { RdfStore } from "rdf-stores";
import { RDF, TREE, XSD } from "@treecg/types";
import { getLoggerFor, getObjects } from "../utils/index.js";
import { SHAPES } from "./shapes.js";
import { Range } from "./range.js";
const df = new DataFactory();
export function empty_condition() {
    return new EmptyCondition();
}
export function parse_condition(source, baseIRI) {
    const shapeQuads = new Parser().parse(SHAPES);
    const output = extractShapes(shapeQuads, {
        "http://vocab.deri.ie/csp#And": (obj) => new AndCondition(obj),
        "http://vocab.deri.ie/csp#MaxCount": (obj) => new MaxCountCondition(obj),
        "http://vocab.deri.ie/csp#Or": (obj) => new OrCondition(obj),
        "http://vocab.deri.ie/csp#Condition": (obj) => new LeafCondition(obj),
    });
    const dataQuads = new Parser({ baseIRI: baseIRI }).parse(source);
    return output.lenses["https://w3id.org/rdf-lens/ontology#TypedExtract"].execute({
        quads: dataQuads,
        id: new NamedNode(baseIRI),
    });
}
export function cbdEquals(a, b) {
    const sort = (a, b) => {
        const ap = a.predicate.value;
        const bp = b.predicate.value;
        if (ap == bp)
            return 0;
        return ap < bp ? -1 : 1;
    };
    const alphaQuads = a.store.getQuads(a.id, null, null, null).sort(sort);
    const betaQuads = b.store.getQuads(b.id, null, null, null).sort(sort);
    if (alphaQuads.length != betaQuads.length)
        return false;
    for (let i = 0; i < alphaQuads.length; i++) {
        if (!alphaQuads[i].predicate.equals(betaQuads[i].predicate)) {
            return false;
        }
        const av = alphaQuads[i].object;
        const bv = betaQuads[i].object;
        if (av.termType !== bv.termType)
            return false;
        if (av.termType === "BlankNode") {
            if (!cbdEquals({ id: av, store: a.store }, { id: bv, store: b.store })) {
                return false;
            }
        }
        else {
            if (av.value !== bv.value) {
                return false;
            }
        }
    }
    return true;
}
export class RelationCondition {
    store;
    defaultTimezone;
    ranges = [];
    constructor(store, defaultTimezone) {
        this.store = store;
        this.defaultTimezone = defaultTimezone;
    }
    allowed(condition) {
        return this.ranges.every((x) => {
            return condition.matchRelation(x.range, {
                id: x.cbdEntry,
                store: this.store,
            });
        });
    }
    addRelation(relationId) {
        const ty = getObjects(this.store, relationId, RDF.terms.type, null)[0] ||
            TREE.Relation;
        const path = getObjects(this.store, relationId, TREE.terms.path, null)[0];
        const value = getObjects(this.store, relationId, TREE.terms.value, null)[0];
        let range = this.ranges.find((range) => cbdEquals({ id: path, store: this.store }, { id: range.cbdEntry, store: this.store }));
        if (!range) {
            const newRange = {
                cbdEntry: path,
                range: Range.empty(this.defaultTimezone),
            };
            this.ranges.push(newRange);
            range = newRange;
        }
        if (!value) {
            range.range = undefined;
            return;
        }
        let dataType;
        if (value.termType === "Literal") {
            dataType = value.datatype.value;
        }
        range.range?.add(value.value, ty.value, dataType);
    }
}
export class LeafCondition {
    relationType;
    value;
    compareType;
    path;
    pathQuads;
    range;
    defaultTimezone;
    logger = getLoggerFor(this);
    constructor(inp) {
        this.relationType = inp.relationType;
        this.value = inp.value;
        this.compareType = inp.compareType || "string";
        this.path = inp.path;
        const store = RdfStore.createDefault();
        inp.pathQuads.quads.forEach((x) => store.addQuad(x));
        this.pathQuads = { id: inp.pathQuads.entry, store };
        this.defaultTimezone = inp.defaultTimezone;
        let dataType;
        if (inp.value.termType === "Literal") {
            dataType = inp.value.datatype.value;
        }
        this.range = new Range(this.parseValue(inp.value.value), inp.relationType.value, this.defaultTimezone, dataType);
    }
    memberEmitted() {
        // empty
    }
    toString() {
        const vts = this.compareType === "date"
            ? (x) => x.toISOString()
            : undefined;
        return `${this.pathQuads.id.value} ∈ ${this.range.toString(vts)}`;
    }
    matchRelation(range, cbdId) {
        if (!cbdEquals(this.pathQuads, cbdId)) {
            return true;
        }
        if (!range) {
            this.logger.debug("[matchRelation] Range is here also undefined, returning false");
            return false;
        }
        const vts = this.compareType === "date"
            ? (x) => new Date(x).toISOString()
            : undefined;
        this.logger.debug(`${this.range.toString(vts)} contains ${range.toString(vts)}. Overlaps: ${this.range.overlaps(range)}`);
        return this.range.overlaps(range);
    }
    matchMember(member) {
        const rawPathValue = this.path.execute(member)[0];
        if (rawPathValue !== undefined) {
            const value = this.parseValue(rawPathValue.id.value);
            return this.range.contains(value);
        }
        else {
            throw new Error(`Property Path <${this.pathQuads.id.value}> does not exist in member <${member.id.value}>`);
        }
    }
    parseValue(value) {
        switch (this.compareType) {
            case "string":
                return value;
            case "date":
                return new Date(value);
            case "integer":
                return parseInt(value);
            case "float":
                return parseFloat(value);
            default:
                return value;
        }
    }
    poll() {
        // pass
    }
}
class BiCondition {
    items;
    constructor(inp) {
        this.items = inp.items;
    }
    matchRelation(range, cbdId) {
        return this.items
            .map((x) => x.matchRelation(range, cbdId))
            .reduce(this.combine.bind(this));
    }
    matchMember(member) {
        return this.items
            .map((x) => x.matchMember(member))
            .reduce(this.combine.bind(this));
    }
    poll() {
        this.items.forEach((x) => x.poll());
    }
}
export class AndCondition extends BiCondition {
    combine(alpha, beta) {
        return alpha && beta; // TODO those might be null if something cannot make a statement about it, important for not condition
    }
    memberEmitted(member) {
        this.items.forEach((x) => x.memberEmitted(member));
    }
    toString() {
        const contents = this.items.map((x) => x.toString()).join(" ^ ");
        return `(${contents})`;
    }
}
export class OrCondition extends BiCondition {
    combine(alpha, beta) {
        return alpha || beta; // TODO those might be null if something cannot make a statement about it, important for not condition
    }
    memberEmitted(member) {
        for (const item of this.items) {
            if (item.matchMember(member)) {
                item.memberEmitted(member);
            }
        }
    }
    toString() {
        const contents = this.items.map((x) => x.toString()).join(" V ");
        return `(${contents})`;
    }
}
export class EmptyCondition {
    matchRelation(_range, _cbdId) {
        return true;
    }
    matchMember(_member) {
        return true;
    }
    memberEmitted() {
        // empty
    }
    toString() {
        return "EmptyCondition (always true)";
    }
    poll() {
        // empty
    }
}
export class MaxCountCondition {
    maxCount;
    current;
    reset_on_poll;
    constructor(inp) {
        this.maxCount = inp.count;
        this.current = 0;
        this.reset_on_poll = inp.reset_on_poll || false;
    }
    matchRelation() {
        return this.current < this.maxCount;
    }
    memberEmitted() {
        this.current += 1;
    }
    matchMember() {
        return this.current < this.maxCount;
    }
    toString() {
        return `${this.current} < ${this.maxCount}`;
    }
    poll() {
        if (this.reset_on_poll) {
            this.current = 0;
        }
    }
}
export async function processConditionFile(conditionFile) {
    let condition = empty_condition();
    /* eslint-disable  @typescript-eslint/no-require-imports */
    const fs = typeof require === "undefined"
        ? await import("fs/promises")
        : require("fs/promises");
    if (conditionFile) {
        try {
            condition = parse_condition(await fs.readFile(conditionFile, { encoding: "utf8" }), conditionFile);
        }
        catch (ex) {
            console.error(`Failed to read condition file: ${conditionFile}`);
            throw ex;
        }
    }
    return condition;
}
/**
 * Function that handles any given condition, together with the "before" and "after" options,
 * and builds the corresponding unified Condition.
 */
export function handleConditions(condition, defaultTimezone, before, after, timestampPath) {
    if ((before || after) && !timestampPath) {
        throw "Cannot apply 'before' or 'after' filters since the target LDES does not define a ldes:timestampPath predicate";
    }
    // Check if before and after conditions are defined and build corresponding Condition object
    let handledCondition = empty_condition();
    const toDateLiteral = (date) => {
        return df.literal(date.toISOString(), XSD.terms.dateTime);
    };
    const predLens = pred(timestampPath);
    if (before) {
        handledCondition = new LeafCondition({
            relationType: TREE.terms.LessThanRelation,
            value: toDateLiteral(before),
            compareType: "date",
            path: predLens,
            pathQuads: { entry: timestampPath, quads: [] },
            defaultTimezone,
        });
    }
    if (after) {
        const afterCond = new LeafCondition({
            relationType: TREE.terms.GreaterThanRelation,
            value: toDateLiteral(after),
            compareType: "date",
            path: predLens,
            pathQuads: { entry: timestampPath, quads: [] },
            defaultTimezone,
        });
        if (handledCondition instanceof EmptyCondition) {
            handledCondition = afterCond;
        }
        else {
            // Got bi-condition with before & after filters
            handledCondition = new AndCondition({
                items: [handledCondition, afterCond],
            });
        }
    }
    // See if condition file was defined too
    if (!(condition instanceof EmptyCondition)) {
        return new AndCondition({
            items: [condition, handledCondition],
        });
    }
    else {
        return handledCondition;
    }
}
